CREATE OR REPLACE FUNCTION mirror_orders() RETURNS trigger AS $$
BEGIN
  INSERT INTO orders_p(id,tenant_id,status,total_cents,created_at)
  VALUES (NEW.id,NEW.tenant_id,NEW.status,NEW.total_cents,NEW.created_at)
  ON CONFLICT (id,tenant_id) DO UPDATE
    SET status=EXCLUDED.status, total_cents=EXCLUDED.total_cents;
  RETURN NEW;
END;$$ LANGUAGE plpgsql;
CREATE TRIGGER trg_mirror_orders AFTER INSERT OR UPDATE ON orders
  FOR EACH ROW EXECUTE FUNCTION mirror_orders();

