async function backfill(cursor) {
  for await (const o of Order.find({ migratedItems: { $ne: true } }).cursor()) {
    const ops = (o.items||[]).map(i => ({ updateOne: {
      filter: { orderId: o._id, sku: i.sku },
      update: { $set: { qty: i.qty, priceCents: i.priceCents } }, upsert: true }}));
    if (ops.length) await OrderItem.bulkWrite(ops, { ordered: false });
    await Order.updateOne({ _id: o._id }, { $set: { migratedItems: true } });
  }
}

