async function decrement(db, sku, qty) {
  const { rows } = await db.query('SELECT stock FROM inventory WHERE sku=$1', [sku]);
  const next = rows[0].stock - qty;
  if (next < 0) throw new Error('oversold');
  await db.query('UPDATE inventory SET stock=$1 WHERE sku=$2', [next, sku]);
}

CREATE TABLE inventory (
  sku TEXT PRIMARY KEY,
  stock INT NOT NULL
);

async function decrement(db, sku, qty, attempt = 0) {
  const { rowCount } = await db.query(
    'UPDATE inventory SET stock = stock - $2, version = version + 1 WHERE sku=$1 AND stock >= $2',
    [sku, qty]
  );
  if (rowCount === 1) return;
  const { rows } = await db.query('SELECT stock FROM inventory WHERE sku=$1', [sku]);
  if (rows[0].stock < qty) throw new Error('oversold');
  if (attempt > 5) throw new Error('contention');
  await new Promise(r => setTimeout(r, 5 * (attempt + 1)));
  return decrement(db, sku, qty, attempt + 1);
}

test('no oversell under 100 concurrent decrements', async () => {
  await seed({ sku: 'X', stock: 50 });
  await Promise.allSettled(Array.from({length:100}, () => decrement(db,'X',1)));
  const { rows } = await db.query('SELECT stock FROM inventory WHERE sku=$1',['X']);
  expect(rows[0].stock).toBe(0); // exactly 50 succeed, 50 oversold-reject
});

