async function apply(db, evt) {
  // idempotent: applied_events dedupes by evt id
  await db.tx(async t => {
    const ins = await t.query('INSERT INTO applied_events(id) VALUES($1) ON CONFLICT DO NOTHING RETURNING 1',[evt.evt]);
    if (!ins.rowCount) return; // already applied
    const d = evt.op === '+1' ? 1 : -1;
    await t.query('UPDATE users SET follower_count = follower_count + $1 WHERE id=$2',[d, evt.followee]);
  });
}

