async function touch(redis, sid) {
  // sliding TTL replaces 40k/sec Postgres UPDATEs
  await redis.expire(`sess:${sid}`, 1800);
}
async function get(redis, db, sid) {
  const cached = await redis.hgetall(`sess:${sid}`);
  if (cached && cached.user_id) return { userId: cached.user_id, expiresAt: cached.expires_at };
  const { rows } = await db.query('SELECT user_id,expires_at FROM sessions WHERE id=$1', [sid]);
  if (!rows[0]) return null;
  await redis.hset(`sess:${sid}`, { user_id: rows[0].user_id, expires_at: rows[0].expires_at });
  await redis.expire(`sess:${sid}`, 1800); // lazy migrate
  return { userId: rows[0].user_id, expiresAt: rows[0].expires_at };
}

async function createSession(redis, db, sid, userId, expiresAt) {
  await redis.hset(`sess:${sid}`, { user_id: userId, expires_at: expiresAt });
  await redis.expire(`sess:${sid}`, 1800);
  if (process.env.SESSION_STORE === 'dual') {
    await db.query('INSERT INTO sessions(id,user_id,expires_at) VALUES($1,$2,$3) ON CONFLICT (id) DO UPDATE SET expires_at=EXCLUDED.expires_at', [sid,userId,expiresAt]);
  }
}

