async function backfill(src, router) {
  let lastId = 0;
  for (;;) {
    const [rows] = await src.query('SELECT * FROM users WHERE id>? ORDER BY id LIMIT 5000', [lastId]);
    if (!rows.length) break;
    for (const u of rows) {
      const pool = router.shardFor(u.id).primary;
      await pool.query('INSERT IGNORE INTO users(id,email,kyc_status) VALUES(?,?,?)', [u.id,u.email,u.kyc_status]);
    }
    lastId = rows[rows.length-1].id;
  }
}

