async function feed(db, { cursor, limit = 20 }) {
  if (!cursor) {
    const { rows } = await db.query('SELECT id,body,created_at FROM posts ORDER BY created_at DESC, id DESC LIMIT $1', [limit]);
    return paginate(rows, limit);
  }
  const { ts, id } = decodeCursor(cursor);
  const { rows } = await db.query(
    'SELECT id,body,created_at FROM posts WHERE (created_at, id) < ($1,$2) ORDER BY created_at DESC, id DESC LIMIT $3',
    [ts, id, limit]
  );
  return paginate(rows, limit);
}
function paginate(rows, limit) {
  const next = rows.length === limit ? encodeCursor(rows[rows.length-1]) : null;
  return { items: rows, nextCursor: next };
}

async function legacyFeed(db, page) {
