  return rows[0].balance_cents;
}

async function readPoolFor(lastWriteLsn) {
  if (!lastWriteLsn) return replica; // no recent write, replica is fine
  const { rows } = await replica.query('SELECT pg_last_wal_replay_lsn() >= $1::pg_lsn AS caught_up', [lastWriteLsn]);
  return rows[0].caught_up ? replica : primary;
}
async function writeReturningLsn(sql, params) {
  const r = await primary.query(sql, params);
  const { rows } = await primary.query('SELECT pg_current_wal_lsn() AS lsn');
  return { result: r, lsn: rows[0].lsn };
}

function attachLsn(req, res, next) {
  req.lastWriteLsn = req.cookies.lwlsn || null;
  res.setWriteLsn = (lsn) => res.cookie('lwlsn', lsn, { maxAge: 5000, httpOnly: true });
  next();
}

async function transfer(route, res, from, to, amt) {
  const { lsn } = await route.writeReturningLsn(
    'UPDATE accounts SET balance_cents = balance_cents - $1 WHERE id=$2', [amt, from]);
  res.setWriteLsn(lsn);
  return lsn;
}

async function balance(route, lastWriteLsn, accountId) {
  const pool = await route.readPoolFor(lastWriteLsn);
  const { rows } = await pool.query('SELECT balance_cents FROM accounts WHERE id=$1', [accountId]);
  return rows[0].balance_cents;
}

