const BLOCK = 100000;
let current = null, end = 0;
async function reserve(db) {
  const { rows } = await db.query(
    'UPDATE id_allocator SET next_block = next_block + 1 WHERE name=$1 RETURNING next_block - 1 AS block', ['impressions']);
  const block = Number(rows[0].block);
  current = block * BLOCK + 1; end = (block + 1) * BLOCK;
}
async function nextId(db) {
  if (current === null || current > end - BLOCK * 0.2) {
    if (current === null || current > end) await reserve(db);
  }
  return current++;
}

