async function join(redis, streamId) { await redis.incr(`viewers:${streamId}`); }
async function leave(redis, streamId) { await redis.decr(`viewers:${streamId}`); }
async function current(redis, streamId) { return Number(await redis.get(`viewers:${streamId}`)); }

const K = 16;
function shardKey(streamId, i) { return `viewers:${streamId}:${i}`; }
async function join(redis, streamId) {
  const i = (Math.random() * K) | 0;
  await redis.incr(shardKey(streamId, i));
}
async function leave(redis, streamId) {
  const i = (Math.random() * K) | 0;
  await redis.decr(shardKey(streamId, i));
}
async function current(redis, streamId) {
  const keys = Array.from({ length: K }, (_, i) => shardKey(streamId, i));
  const vals = await redis.mget(...keys); // cluster client splits by slot
  return vals.reduce((a, v) => a + Number(v || 0), 0);
}

async function migrate(redis, streamId) {
  const old = Number(await redis.get(`viewers:${streamId}`)) || 0;
  if (old) await redis.incrby(`viewers:${streamId}:0`, old); // fold legacy count into shard 0
  await redis.del(`viewers:${streamId}`);
}

