CREATE TABLE saga_state (
  order_id TEXT PRIMARY KEY,
  step TEXT NOT NULL,
  status TEXT NOT NULL,
  updated_at TIMESTAMPTZ NOT NULL DEFAULT now()
);

async function advance(db, order) {
  await setStep(db, order.id, 'CREATE');
  await orderSvc.create(order); // idempotent by order.id
  await setStep(db, order.id, 'CHARGE');
  await paymentSvc.charge(order); // idempotent by idempotency-key=order.id
  await setStep(db, order.id, 'RESERVE');
  try {
    await inventorySvc.reserve(order);
    await setStep(db, order.id, 'DONE');
  } catch (e) {
    await setStep(db, order.id, 'COMPENSATING');
    await emitCompensation(order.id, 'REFUND');
    throw e;
  }
}

async function onCompensation(db, evt) {
  if (evt.type === 'REFUND') {
    await paymentSvc.refund(evt.orderId, { idempotencyKey: `refund:${evt.orderId}` }); // safe to retry
    await setStep(db, evt.orderId, 'COMPENSATED');
  }
}

// retries compensations until success; only dead-letters after N attempts
async function processWithRetry(handler, evt, max = 8) {
  for (let i = 0; i < max; i++) {
    try { return await handler(evt); } catch { await sleep(2 ** i * 100); }
  }
  await deadLetter(evt); // manual review only as last resort
}

