CREATE TABLE shipments (
  id BIGINT PRIMARY KEY,
  address TEXT NOT NULL
);

async function create(db, s) {
  await db.query('INSERT INTO shipments(id,address) VALUES($1,$2)', [s.id, s.address]);
}

CREATE TABLE addresses (
  shipment_id BIGINT PRIMARY KEY REFERENCES shipments(id),
  street TEXT, city TEXT, postal TEXT, country TEXT,
  parsed BOOLEAN NOT NULL DEFAULT false
);
CREATE INDEX idx_addr_country_postal ON addresses(country, postal);

async function create(db, s) {
  await db.tx(async t => {
    await t.query('INSERT INTO shipments(id,address) VALUES($1,$2)', [s.id, s.address]);
    const p = parseAddress(s.address);
    await t.query('INSERT INTO addresses(shipment_id,street,city,postal,country,parsed) VALUES($1,$2,$3,$4,$5,$6)',
      [s.id, p.street, p.city, p.postal, p.country, p.ok]);
    if (!p.ok) await t.query('INSERT INTO address_review(shipment_id,raw) VALUES($1,$2)', [s.id, s.address]);
  });
}

async function backfill(db) {
  let last = 0;
  for (;;) {
    const { rows } = await db.query('SELECT id,address FROM shipments WHERE id>$1 ORDER BY id LIMIT 5000', [last]);
    if (!rows.length) break;
    for (const s of rows) {
      const p = parseAddress(s.address);
      await db.query('INSERT INTO addresses(shipment_id,street,city,postal,country,parsed) VALUES($1,$2,$3,$4,$5,$6) ON CONFLICT (shipment_id) DO NOTHING', [s.id,p.street,p.city,p.postal,p.country,p.ok]);
      if (!p.ok) await db.query('INSERT INTO address_review(shipment_id,raw) VALUES($1,$2) ON CONFLICT DO NOTHING', [s.id,s.address]);
    }
    last = rows[rows.length-1].id;
  }
}

