CREATE TABLE comments (
  id BIGINT PRIMARY KEY,
  commentable_type TEXT NOT NULL, -- 'issue'|'pr'|'commit'
  commentable_id BIGINT NOT NULL,
  body TEXT NOT NULL
);

async function forParent(db, type, id) {
  return db.query('SELECT id,body FROM comments WHERE commentable_type=$1 AND commentable_id=$2', [type, id]);
}

UPDATE comments SET issue_id = commentable_id WHERE commentable_type='issue' AND issue_id IS NULL AND id BETWEEN $1 AND $2;
UPDATE comments SET pr_id = commentable_id WHERE commentable_type='pr' AND pr_id IS NULL AND id BETWEEN $1 AND $2;
UPDATE comments SET commit_id = commentable_id WHERE commentable_type='commit' AND commit_id IS NULL AND id BETWEEN $1 AND $2;

async function add(db, parentType, parentId, body) {
  const col = { issue: 'issue_id', pr: 'pr_id', commit: 'commit_id' }[parentType];
  await db.query(`INSERT INTO comments(id,${col},body) VALUES(nextval('comments_id_seq'),$1,$2)`, [parentId, body]);
}

