-- BRIN is ~99% smaller; effective because logs are physically time-ordered
CREATE INDEX CONCURRENTLY idx_logs_ts_brin ON logs USING brin (ts) WITH (pages_per_range = 32);
ANALYZE logs;

async function range(db, from, to) {
