  return db.query('SELECT ts,level,msg FROM logs WHERE ts BETWEEN $1 AND $2', [from, to]);
}

async function inTransitByRegion(shards) {
  const parts = await Promise.all(shards.map(s => s.query("SELECT region, count(*) c FROM parcels WHERE status='IN_TRANSIT' GROUP BY region")));
  // merge in app
  return mergeCounts(parts);
}

CREATE TABLE region_status_counts (
  region TEXT NOT NULL,
  status TEXT NOT NULL,
  cnt BIGINT NOT NULL DEFAULT 0,
  PRIMARY KEY (region, status)
);

async function onStatusChange(db, evt) {
  // evt: { region, from, to, delta:1 } ; idempotent via event id
  await db.tx(async t => {
    const ins = await t.query('INSERT INTO projected_events(id) VALUES($1) ON CONFLICT DO NOTHING RETURNING 1', [evt.id]);
    if (!ins.rowCount) return;
    if (evt.from) await t.query('UPDATE region_status_counts SET cnt=cnt-1 WHERE region=$1 AND status=$2', [evt.region, evt.from]);
    await t.query('INSERT INTO region_status_counts(region,status,cnt) VALUES($1,$2,1) ON CONFLICT (region,status) DO UPDATE SET cnt=region_status_counts.cnt+1', [evt.region, evt.to]);
  });
}

async function inTransitByRegion(readDb) {
  // single fast read from the projection, no scatter-gather
  return readDb.query("SELECT region, cnt FROM region_status_counts WHERE status='IN_TRANSIT'");
}

async function reconcile(shards, readDb) {
  const truth = mergeCounts(await Promise.all(shards.map(s => s.query("SELECT region,status,count(*) c FROM parcels GROUP BY region,status"))));
  for (const r of truth) await readDb.query('INSERT INTO region_status_counts(region,status,cnt) VALUES($1,$2,$3) ON CONFLICT (region,status) DO UPDATE SET cnt=EXCLUDED.cnt', [r.region,r.status,r.c]);
}

async function page(db, offsetAmount, limit) {
  return db.query('SELECT id, amount FROM transactions WHERE amount > $1 ORDER BY amount LIMIT $2', [offsetAmount, limit]);
}

async function page(db, cursor, limit) {
  if (!cursor) {
    return db.query('SELECT id, amount FROM transactions ORDER BY amount, id LIMIT $1', [limit]);
  }
  // composite keyset: strictly after (amount,id)
  return db.query(
    'SELECT id, amount FROM transactions WHERE (amount, id) > ($1,$2) ORDER BY amount, id LIMIT $3',
    [cursor.amount, cursor.id, limit]
  );
}

async function create(db, post) {
  await db.query('INSERT INTO posts(id,author_id,body) VALUES($1,$2,$3)', [post.id, post.authorId, post.body]);
  const followers = await db.query('SELECT follower_id FROM follows WHERE followee_id=$1', [post.authorId]);
  for (const f of followers.rows) {
    await db.query('INSERT INTO feeds(user_id,post_id) VALUES($1,$2)', [f.follower_id, post.id]);
