}

async function create(db, post) {
  await db.tx(async t => {
    await t.query('INSERT INTO posts(id,author_id,body) VALUES($1,$2,$3)', [post.id, post.authorId, post.body]);
    await t.query('INSERT INTO outbox(topic,payload) VALUES($1,$2)', ['fanout', JSON.stringify({ postId: post.id, authorId: post.authorId })]);
  });
  // returns immediately; fan-out happens async
}

CREATE TABLE feeds (
  user_id BIGINT NOT NULL,
  post_id BIGINT NOT NULL,
  PRIMARY KEY (user_id, post_id)
);

async function fanout(db, evt) {
  let last = 0;
  for (;;) {
    const { rows } = await db.query('SELECT follower_id FROM follows WHERE followee_id=$1 AND follower_id>$2 ORDER BY follower_id LIMIT 5000', [evt.authorId, last]);
    if (!rows.length) break;
    const values = rows.map(r => `(${r.follower_id},${evt.postId})`).join(',');
    await db.query(`INSERT INTO feeds(user_id,post_id) VALUES ${values} ON CONFLICT DO NOTHING`);
    last = rows[rows.length-1].follower_id;
  }
}

async function consumeWithRetry(handler, evt) {
  for (let i=0;i<10;i++){ try { return await handler(evt); } catch { await sleep(2**i*100); } }
  await deadLetter(evt);
}
